using namespace std;

int main() {
    int n, k, x;
    cin >> n >> k >> x;
    vector<int> P(n);
    int pos = -1;
    for (int i = 0; i < n; i++) {
        cin >> P[i];
        if (P[i] == x) pos = i;
    }
    int shift = (pos - k + n) % n;
    vector<int> ans(n);
    for (int i = 0; i < n; i++) {
        ans[i] = P[(i + shift) % n];
    }
    for (int i = 0; i < n; i++) {
        cout << ans[i] << " \n"[i == n - 1];
    }
    return 0;
}
